// Extrait et valide les critères de recherche
const input = $input.first().json;

// Configuration Firecrawl et Ollama (URLs Docker internes Coolify)
const FIRECRAWL_API_URL = $env.FIRECRAWL_API_URL || 'http://api-g48kgskgo8cooksg48s84coc-162904357390:3002';
const OLLAMA_API_URL = $env.OLLAMA_API_URL || 'http://ollama-n04oocg8o8k088ws8k4kss4g:11434';

const searchCriteria = {
  query: input.query || input.searchQuery || '',
  location: input.location || 'France',
  contract_type: input.contract_type || input.contractType || 'all',
  experience_level: input.experience_level || input.experienceLevel || 'all',
  remote: input.remote || false,
  salary_min: input.salary_min || input.salaryMin || null,
  salary_max: input.salary_max || input.salaryMax || null,
  max_results: input.max_results || input.maxResults || 20,
  selected_sites: input.selected_sites || input.selectedSites || ['indeed', 'linkedin', 'malt', 'free-work', 'wttj'],
  user_id: input.user_id || input.userId || null,
  user_email: input.user_email || input.userEmail || null,
  session_id: input.session_id || `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  timestamp: new Date().toISOString(),
  firecrawl_url: FIRECRAWL_API_URL,
  ollama_url: OLLAMA_API_URL
};

if (!searchCriteria.query || searchCriteria.query.trim() === '') {
  throw new Error('Le champ "query" est requis pour effectuer une recherche');
}

console.log('=== Critères de recherche validés ===');
console.log('Query:', searchCriteria.query);
console.log('Location:', searchCriteria.location);
console.log('Firecrawl URL:', FIRECRAWL_API_URL);
console.log('Ollama URL:', OLLAMA_API_URL);

return { json: searchCriteria };

// Prépare les URLs de recherche pour chaque site
const criteria = $node['Validate Search Criteria'].json;
const selectedSites = criteria.selected_sites;

const siteConfigs = {
  'indeed': {
    name: 'Indeed',
    searchUrl: `https://fr.indeed.com/emplois?q=${encodeURIComponent(criteria.query)}&l=${encodeURIComponent(criteria.location)}`,
    jobUrlPattern: '/viewjob',
    category: 'cdi_cdd'
  },
  'linkedin': {
    name: 'LinkedIn Jobs',
    searchUrl: `https://www.linkedin.com/jobs/search?keywords=${encodeURIComponent(criteria.query)}&location=${encodeURIComponent(criteria.location)}`,
    jobUrlPattern: '/jobs/view/',
    category: 'cdi_cdd'
  },
  'malt': {
    name: 'Malt',
    searchUrl: `https://www.malt.fr/s?q=${encodeURIComponent(criteria.query)}&searchCity=${encodeURIComponent(criteria.location)}`,
    jobUrlPattern: '/project/',
    category: 'freelance'
  },
  'free-work': {
    name: 'Free-Work',
    searchUrl: `https://www.free-work.com/fr/tech-it/jobs?query=${encodeURIComponent(criteria.query)}&localisation=${encodeURIComponent(criteria.location)}`,
    jobUrlPattern: '/job/',
    category: 'freelance'
  },
  'wttj': {
    name: 'Welcome to the Jungle',
    searchUrl: `https://www.welcometothejungle.com/fr/jobs?query=${encodeURIComponent(criteria.query)}&aroundQuery=${encodeURIComponent(criteria.location)}`,
    jobUrlPattern: '/jobs/',
    category: 'cdi_cdd'
  }
};

const scrapingTasks = selectedSites
  .filter(site => siteConfigs[site])
  .map(site => {
    const config = siteConfigs[site];
    return {
      site_id: site,
      site_name: config.name,
      category: config.category,
      search_url: config.searchUrl,
      job_url_pattern: config.jobUrlPattern,
      query: criteria.query,
      location: criteria.location,
      max_results: Math.ceil(criteria.max_results / selectedSites.length),
      session_id: criteria.session_id,
      user_id: criteria.user_id,
      firecrawl_url: criteria.firecrawl_url,
      ollama_url: criteria.ollama_url
    };
  });

return scrapingTasks.map(task => ({ json: task }));

// Extrait les URLs d'offres depuis les résultats Firecrawl
const task = $node['Split In Batches'].json;
const firecrawlResult = $input.first().json;

if (!firecrawlResult.success || !firecrawlResult.data) {
  console.log(`Erreur Firecrawl pour ${task.site_name}:`, firecrawlResult.error);
  return [];
}

const links = firecrawlResult.data.links || [];
const jobUrlPattern = task.job_url_pattern;

// Filtrer les liens d'offres d'emploi
const jobLinks = links
  .filter(link => link.includes(jobUrlPattern))
  .slice(0, task.max_results);

console.log(`${task.site_name}: ${jobLinks.length} offres trouvées`);

// Préparer les tâches de scraping individuel
return jobLinks.map((url, index) => ({
  json: {
    job_url: url,
    site_id: task.site_id,
    site_name: task.site_name,
    category: task.category,
    session_id: task.session_id,
    index: index,
    firecrawl_url: task.firecrawl_url,
    ollama_url: task.ollama_url,
    query: task.query,
    location: task.location
  }
}));

// Prépare le prompt pour Ollama
const jobData = $node['Extract Job URLs'].json;
const firecrawlResult = $input.first().json;

if (!firecrawlResult.success || !firecrawlResult.data?.markdown) {
  return {
    json: {
      error: 'Failed to scrape job page',
      ...jobData
    }
  };
}

const jobMarkdown = firecrawlResult.data.markdown;
const metadata = firecrawlResult.data.metadata || {};

// Prompt d'extraction structurée pour Ollama
const extractionPrompt = `Tu es un expert en extraction de données d'offres d'emploi.
Extrait les informations suivantes de cette offre et retourne UNIQUEMENT un objet JSON valide.

Format attendu:
{
  "title": "Titre exact du poste",
  "company": "Nom de l'entreprise",
  "location": "Ville, Pays",
  "salary": "Salaire si mentionné, sinon null",
  "contract_type": "CDI|CDD|Freelance|Stage|Alternance|Autre",
  "experience_required": "Junior|Confirmé|Senior|Lead|Non précisé",
  "remote_policy": "Sur site|Hybride|Full remote|Non précisé",
  "skills": ["skill1", "skill2"],
  "description": "Résumé court de l'offre (max 200 caractères)"
}

OFFRE D'EMPLOI:
${jobMarkdown.substring(0, 6000)}

Réponds UNIQUEMENT avec le JSON, sans texte avant ou après.`;

return {
  json: {
    ...jobData,
    job_markdown: jobMarkdown,
    page_title: metadata.title || '',
    extraction_prompt: extractionPrompt
  }
};

// Parse la réponse Ollama et structure les données
const prevData = $node['Prepare Ollama Extraction'].json;
const ollamaResult = $input.first().json;

let extractedData = {};

try {
  // Extraire le JSON de la réponse Ollama
  const response = ollamaResult.response || '';
  const jsonMatch = response.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    extractedData = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.log('Erreur parsing Ollama:', e.message);
  // Fallback avec données basiques
  extractedData = {
    title: prevData.page_title || 'Offre d\'emploi',
    company: 'Non précisé',
    location: prevData.location || 'France',
    salary: null,
    contract_type: prevData.category === 'freelance' ? 'Freelance' : 'CDI',
    experience_required: 'Non précisé',
    remote_policy: 'Non précisé',
    skills: [],
    description: prevData.job_markdown?.substring(0, 200) || ''
  };
}

// Construire l'objet job final
const job = {
  id: `${prevData.site_id}_${prevData.session_id}_${prevData.index}`,
  session_id: prevData.session_id,
  source: prevData.site_id,
  site_name: prevData.site_name,
  url: prevData.job_url,
  title: extractedData.title || 'Offre d\'emploi',
  company: extractedData.company || 'Non précisé',
  location: extractedData.location || prevData.location,
  salary: extractedData.salary,
  contract_type: extractedData.contract_type || (prevData.category === 'freelance' ? 'Freelance' : 'CDI'),
  experience_level: extractedData.experience_required || 'Non précisé',
  remote: extractedData.remote_policy || 'Non précisé',
  skills: extractedData.skills || [],
  description: extractedData.description || prevData.job_markdown?.substring(0, 300) || '',
  posted_date: new Date().toISOString(),
  scraped_at: new Date().toISOString()
};

return { json: job };

// Déduplique les offres similaires
const allJobs = $input.all().map(item => item.json).filter(job => job.title && !job.error);

console.log(`=== Déduplication ===`);
console.log(`Offres avant déduplication: ${allJobs.length}`);

function normalize(str) {
  return (str || '').toLowerCase().trim().replace(/[^a-z0-9]/g, '');
}

function similarity(str1, str2) {
  const s1 = new Set(normalize(str1).split(''));
  const s2 = new Set(normalize(str2).split(''));
  const intersection = new Set([...s1].filter(x => s2.has(x)));
  const union = new Set([...s1, ...s2]);
  return union.size > 0 ? intersection.size / union.size : 0;
}

const uniqueJobs = [];
const seenSignatures = new Map();

for (const job of allJobs) {
  const signature = `${normalize(job.title)}_${normalize(job.company)}`;
  let isDuplicate = false;

  for (const [existingSignature, existingJob] of seenSignatures) {
    const titleSim = similarity(job.title, existingJob.title);
    const companySim = similarity(job.company, existingJob.company);

    if (titleSim > 0.8 && companySim > 0.7) {
      isDuplicate = true;
      console.log(`Doublon: "${job.title}" (${job.source}) ~ "${existingJob.title}" (${existingJob.source})`);
      break;
    }
  }

  if (!isDuplicate) {
    seenSignatures.set(signature, job);
    uniqueJobs.push(job);
  }
}

console.log(`Offres après déduplication: ${uniqueJobs.length}`);
uniqueJobs.sort((a, b) => new Date(b.posted_date) - new Date(a.posted_date));

return uniqueJobs.map(job => ({ json: job }));

// Génère la page HTML des résultats
const allJobs = $input.all().map(item => item.json);
const criteria = $node['Validate Search Criteria'].json;

const jobsBySource = {};
for (const job of allJobs) {
  if (!jobsBySource[job.source]) jobsBySource[job.source] = [];
  jobsBySource[job.source].push(job);
}

const sourceColors = {
  'indeed': '#2164f3',
  'linkedin': '#0a66c2',
  'malt': '#fc5757',
  'free-work': '#00b4d8',
  'wttj': '#ffcd00'
};

const sourceNames = {
  'indeed': 'Indeed',
  'linkedin': 'LinkedIn',
  'malt': 'Malt',
  'free-work': 'Free-Work',
  'wttj': 'Welcome to the Jungle'
};

function formatDate(dateStr) {
  const date = new Date(dateStr);
  const now = new Date();
  const diffDays = Math.floor((now - date) / (1000 * 60 * 60 * 24));
  if (diffDays === 0) return "Aujourd'hui";
  if (diffDays === 1) return 'Hier';
  if (diffDays < 7) return `Il y a ${diffDays} jours`;
  return date.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' });
}

let jobCardsHtml = '';
for (const job of allJobs) {
  const sourceColor = sourceColors[job.source] || '#6c757d';
  const sourceName = sourceNames[job.source] || job.source;
  const remoteIcon = job.remote?.toLowerCase().includes('remote') || job.remote?.toLowerCase().includes('télétravail') ? '🏠' : '🏢';
  const contractIcon = job.contract_type === 'Freelance' ? '💼' : '📋';
  const skillsHtml = (job.skills || []).slice(0, 3).map(s => `<span class="skill">${s}</span>`).join('');

  jobCardsHtml += `
    <div class="job-card" data-source="${job.source}">
      <div class="job-header">
        <span class="source-badge" style="background-color: ${sourceColor}">${sourceName}</span>
        <span class="posted-date">${formatDate(job.posted_date)}</span>
      </div>
      <h3 class="job-title"><a href="${job.url}" target="_blank">${job.title}</a></h3>
      <div class="job-company"><strong>${job.company}</strong></div>
      <div class="job-details">
        <span class="detail">📍 ${job.location}</span>
        <span class="detail">${contractIcon} ${job.contract_type}</span>
        <span class="detail">${remoteIcon} ${job.remote || 'Non précisé'}</span>
        ${job.salary ? `<span class="detail">💰 ${job.salary}</span>` : ''}
        ${job.experience_level && job.experience_level !== 'Non précisé' ? `<span class="detail">📊 ${job.experience_level}</span>` : ''}
      </div>
      ${skillsHtml ? `<div class="skills">${skillsHtml}</div>` : ''}
      <p class="job-description">${(job.description || '').substring(0, 180)}...</p>
      <a href="${job.url}" target="_blank" class="apply-btn">Voir l'offre →</a>
    </div>`;
}

let statsHtml = '';
for (const [source, jobs] of Object.entries(jobsBySource)) {
  const color = sourceColors[source] || '#6c757d';
  const name = sourceNames[source] || source;
  statsHtml += `<span class="stat-badge" style="background-color: ${color}">${name}: ${jobs.length}</span>`;
}

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Résultats - ${criteria.query} | JobNexAI</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); min-height: 100vh; padding: 20px; }
    .container { max-width: 1200px; margin: 0 auto; }
    .header { background: white; border-radius: 16px; padding: 24px; margin-bottom: 24px; box-shadow: 0 10px 40px rgba(0,0,0,0.1); }
    .header h1 { color: #1a1a2e; font-size: 28px; margin-bottom: 8px; }
    .search-info { color: #6c757d; font-size: 14px; margin-bottom: 16px; }
    .stats { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 16px; }
    .stat-badge, .total-badge { color: white; padding: 6px 12px; border-radius: 20px; font-size: 13px; font-weight: 500; }
    .total-badge { background: linear-gradient(135deg, #667eea, #764ba2); padding: 8px 16px; font-weight: 600; }
    .filters { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 16px; }
    .filter-btn { background: #f8f9fa; border: 2px solid #e9ecef; padding: 8px 16px; border-radius: 20px; cursor: pointer; font-size: 13px; transition: all 0.2s; }
    .filter-btn:hover, .filter-btn.active { background: #667eea; border-color: #667eea; color: white; }
    .jobs-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(350px, 1fr)); gap: 20px; }
    .job-card { background: white; border-radius: 12px; padding: 20px; box-shadow: 0 4px 20px rgba(0,0,0,0.08); transition: transform 0.2s, box-shadow 0.2s; }
    .job-card:hover { transform: translateY(-4px); box-shadow: 0 8px 30px rgba(0,0,0,0.12); }
    .job-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px; }
    .source-badge { color: white; padding: 4px 10px; border-radius: 12px; font-size: 11px; font-weight: 600; text-transform: uppercase; }
    .posted-date { color: #6c757d; font-size: 12px; }
    .job-title { font-size: 18px; margin-bottom: 8px; line-height: 1.3; }
    .job-title a { color: #1a1a2e; text-decoration: none; }
    .job-title a:hover { color: #667eea; }
    .job-company { color: #495057; margin-bottom: 12px; font-size: 15px; }
    .job-details { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 12px; }
    .detail { background: #f8f9fa; padding: 4px 8px; border-radius: 6px; font-size: 12px; color: #495057; }
    .skills { display: flex; gap: 6px; margin-bottom: 12px; }
    .skill { background: #e8f4f8; color: #0077b5; padding: 3px 8px; border-radius: 4px; font-size: 11px; }
    .job-description { color: #6c757d; font-size: 13px; line-height: 1.5; margin-bottom: 16px; }
    .apply-btn { display: inline-block; background: linear-gradient(135deg, #667eea, #764ba2); color: white; padding: 10px 20px; border-radius: 8px; text-decoration: none; font-weight: 500; font-size: 14px; transition: transform 0.2s, box-shadow 0.2s; }
    .apply-btn:hover { transform: translateY(-2px); box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4); }
    .powered-by { text-align: center; margin-top: 40px; color: white; opacity: 0.8; font-size: 14px; }
    .powered-by a { color: white; }
    @media (max-width: 768px) { .jobs-grid { grid-template-columns: 1fr; } .header h1 { font-size: 22px; } }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🔍 Résultats pour "${criteria.query}"</h1>
      <p class="search-info">📍 ${criteria.location} • 🤖 Propulsé par Firecrawl + Ollama • ${new Date().toLocaleDateString('fr-FR')}</p>
      <div class="stats">
        <span class="total-badge">📊 ${allJobs.length} offres trouvées</span>
        ${statsHtml}
      </div>
      <div class="filters">
        <button class="filter-btn active" onclick="filterJobs('all')">Tous</button>
        <button class="filter-btn" onclick="filterJobs('cdi')">CDI/CDD</button>
        <button class="filter-btn" onclick="filterJobs('freelance')">Freelance</button>
        ${Object.keys(jobsBySource).map(s => `<button class="filter-btn" onclick="filterJobs('${s}')">${sourceNames[s] || s}</button>`).join('')}
      </div>
    </div>
    <div class="jobs-grid">${jobCardsHtml}</div>
    <div class="powered-by">Propulsé par <a href="https://jobnexai.com">JobNexAI</a> • Session: ${criteria.session_id}</div>
  </div>
  <script>
    function filterJobs(filter) {
      document.querySelectorAll('.filter-btn').forEach(btn => btn.classList.remove('active'));
      event.target.classList.add('active');
      document.querySelectorAll('.job-card').forEach(card => {
        const source = card.dataset.source;
        let show = filter === 'all' || source === filter || (filter === 'cdi' && ['indeed','linkedin','wttj'].includes(source)) || (filter === 'freelance' && ['malt','free-work'].includes(source));
        card.style.display = show ? 'block' : 'none';
      });
    }
  </script>
</body>
</html>`;

return { json: { html, session_id: criteria.session_id, total_jobs: allJobs.length, jobs_by_source: Object.fromEntries(Object.entries(jobsBySource).map(([k,v]) => [k, v.length])) } };
